import{_ as c,W as d,X as t,$ as a,a2 as e,a0 as n,C as p,Z as i}from"./framework-174e6972.js";const l={},o=n(`<h2 id="聚合函数" tabindex="-1"><a class="header-anchor" href="#聚合函数" aria-hidden="true">#</a> 聚合函数：</h2><p><code>SQL</code>中提供的聚合函数可以用来统计、求和、求最值等等。</p><p>分类：</p><ul><li><p><code>COUNT</code>：统计行数量</p></li><li><p><code>SUM</code>：获取单个列的合计值</p></li><li><p><code>AVG</code>：计算某个列的平均值</p></li><li><p><code>MAX</code>：计算列的最大值</p></li><li><p><code>MIN</code>：计算列的最小值</p></li></ul><p>首先，创建数据表如下：</p><figure><img src="https://pic.downk.cc/item/5e858f04504f4bcb04d5769e.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="执行列、行计数-count" tabindex="-1"><a class="header-anchor" href="#执行列、行计数-count" aria-hidden="true">#</a> 执行列、行计数（count）</h3><p>标准格式</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">&lt;</span> 计数规范 <span class="token operator">&gt;</span><span class="token punctuation">)</span>
<span class="token keyword">FROM</span> <span class="token operator">&lt;</span> 表名 <span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中，计数规范包括：</p><ul><li><p><code>*</code>:计数所有选择的行，包括NULL值；</p></li><li><p><code>ALL </code>列名：计数指定列的所有非空值行，如果不写，默认为<code>ALL</code>；</p></li><li><p><code>DISTINCT</code> 列名：计数指定列的唯一非空值行。</p></li></ul><p><strong>例，计算班里共有多少学生：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e858f75504f4bcb04d5bfd2.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><strong>也可加入筛选条件，如求女学生数目：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_sex <span class="token operator">=</span> <span class="token string">&#39;女&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e858fba504f4bcb04d5f5c2.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><strong>如果要计算班级数目，就需要用到<code>DISTINCT</code>：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token keyword">DISTINCT</span> student_class<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e858ffe504f4bcb04d637e9.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><code>DISTINCT</code>即去重，如果不加<code>DISTINCT</code>则结果为表行数——5。</p><h3 id="返回列合计值-sum" tabindex="-1"><a class="header-anchor" href="#返回列合计值-sum" aria-hidden="true">#</a> 返回列合计值（SUM）</h3>`,22),r=n(`<p><strong>计算学生年龄之和：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">SUM</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e8591b6504f4bcb04d765aa.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="返回列平均值-avg" tabindex="-1"><a class="header-anchor" href="#返回列平均值-avg" aria-hidden="true">#</a> 返回列平均值（AVG）</h3><p><strong>计算学生平均年龄：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">AVG</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e8591db504f4bcb04d782a2.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="返回最大值-最小值-max-min" tabindex="-1"><a class="header-anchor" href="#返回最大值-最小值-max-min" aria-hidden="true">#</a> 返回最大值/最小值（MAX/MIN）</h3><p><strong>求年龄最大的学生信息（最小值同理）</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token function">MAX</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e8591f9504f4bcb04d797a4.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>`,11),u=n(`<h2 id="数据分组-group-by" tabindex="-1"><a class="header-anchor" href="#数据分组-group-by" aria-hidden="true">#</a> 数据分组（GROUP BY)</h2><p><code>SQL</code>中数据可以按列名分组，搭配聚合函数十分实用。</p><p>例，统计每个班的人数:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  student_class<span class="token punctuation">,</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token keyword">ALL</span> student_name<span class="token punctuation">)</span> <span class="token keyword">AS</span> 总人数
<span class="token keyword">FROM</span> t_student
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span>
  <span class="token punctuation">(</span>student_class<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>AS</code>为定义别名，别名的使用在组合及联接查询时会有很好的效果，之后再说。</p><figure><img src="https://pic.downk.cc/item/5e85922e504f4bcb04d7bdd7.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>分组中也可以加入筛选条件<code>WHERE</code>，不过这里一定要注意的是，执行顺序为：</p><ol><li><code>WHERE</code>过滤</li><li>分组</li><li>聚合函数。</li></ol>`,8),v=n(`<p><strong>统计每个班上20岁以上的学生人数：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  student_class<span class="token punctuation">,</span>
  <span class="token function">COUNT</span><span class="token punctuation">(</span>student_name<span class="token punctuation">)</span> <span class="token keyword">AS</span> 总人数
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_age <span class="token operator">&gt;</span> <span class="token number">20</span>
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span>
  <span class="token punctuation">(</span>student_class<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e859258504f4bcb04d7de5a.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="having过滤条件" tabindex="-1"><a class="header-anchor" href="#having过滤条件" aria-hidden="true">#</a> HAVING过滤条件</h3><p>之前说了分组操作、聚合函数、<code>WHERE</code>过滤的执行顺序，那如果我们希望在聚合之后执行过滤条件怎么办？</p><p>例，我们想查询平均年龄在20岁以上的班级</p><p>能用下面的语句吗？</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  student_class<span class="token punctuation">,</span>
  <span class="token function">AVG</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  <span class="token function">AVG</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">20</span>
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span>
  student_class<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>结果会出错。正因为聚合函数在<code>WHERE</code>之后执行，所以这里在<code>WHERE</code>判断条件里加入聚合函数是做不到的。</p><p>这里使用<code>HAIVING</code>即可完成：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  student_class<span class="token punctuation">,</span>
  <span class="token function">AVG</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span> <span class="token keyword">AS</span> 平均年龄
<span class="token keyword">FROM</span> t_student
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span>
  <span class="token punctuation">(</span>student_class<span class="token punctuation">)</span>
<span class="token keyword">HAVING</span>
  <span class="token function">AVG</span><span class="token punctuation">(</span>student_age<span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">20</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e859290504f4bcb04d808b0.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这里再啰嗦一句</p><p><strong><code>SQL</code>的执行顺序：</strong></p><ul><li><p>第一步：执行<code>FROM</code></p></li><li><p>第二步：<code>WHERE</code>条件过滤</p></li><li><p>第三步：<code>GROUP BY</code>分组</p></li><li><p>第四步：执行<code>SELECT</code>投影列</p></li><li><p>第五步：<code>HAVING</code>条件过滤</p></li><li><p>第六步：执行<code>ORDER BY</code> 排序</p></li></ul><h2 id="子查询" tabindex="-1"><a class="header-anchor" href="#子查询" aria-hidden="true">#</a> 子查询：</h2><p>为什么要子查询？</p><p>现有一数据表如下：</p><p><img src="https://pic.downk.cc/item/5e8592b7504f4bcb04d825d3.jpg" alt="" loading="lazy"> 根据之前的知识我们可以查出每门科目的最高分，但是要想查出取得最高分的学生信息就做不到了。这时就需要用到子查询来取得完整的信息。</p><p>什么是子查询？子查询就是嵌套在主查询中的查询。</p><p>子查询可以嵌套在主查询中所有位置，包括<code>SELECT</code>、<code>FROM</code>、<code>WHERE</code>、<code>GROUP BY</code>、<code>HAVING</code>、<code>ORDER BY</code>。</p><p>但并不是每个位置嵌套子查询都是有意义并实用的，这里对几种有实际意义的子查询进行说明。</p><p>现有表两张：一张学生表、一张班表。<code>id</code>相关联</p><figure><img src="https://pic.downk.cc/item/5e8592df504f4bcb04d84202.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="https://pic.downk.cc/item/5e8592eb504f4bcb04d84c01.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="在select中嵌套" tabindex="-1"><a class="header-anchor" href="#在select中嵌套" aria-hidden="true">#</a> 在SELECT中嵌套</h3><p>学生信息和班级名称位于不同的表中，要在同一张表中查出学生的学号、姓名、班级名称：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  s<span class="token punctuation">.</span>student_id<span class="token punctuation">,</span>
  s<span class="token punctuation">.</span>student_name<span class="token punctuation">,</span><span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span>
      class_name
    <span class="token keyword">FROM</span> t_class c
    <span class="token keyword">WHERE</span>
      c<span class="token punctuation">.</span>class_id <span class="token operator">=</span> s<span class="token punctuation">.</span>class_id
  <span class="token punctuation">)</span>
<span class="token keyword">FROM</span> t_student s
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span>
  s<span class="token punctuation">.</span>student_id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>首先这条<code>SQL</code>语句用到了别名，写法为在<code>FORM</code>的表名后加上某个字符比如<code>FROM t_student s，</code>这样在之后调用<code>t_student</code>的某一列时就可以用<code>s.student_id来</code>强调此列来源于对应别名的那张表。</p><p>别名在子查询及联接查询中的应用有着很好效果，当两张表有相同列名或者为了加强可读性，给表加上不同的别名，就能很好的区分哪些列属于哪张表。</p><p>还有种情况就是在子查询或联接查询时，主查询及子查询均为对同一张表进行操作，为主、子查询中的表加上不同的别名能够很好的区分哪些列的操作是在主查询中进行的，哪些列的操作是在子查询中进行的，下文会有实例说明。</p><p>接下来回到上面的<code>SQL</code>语句中，可以看出本条子查询的嵌套是在<code>SELECT</code>位置（括号括起来的部分），它与学号、学生姓名以逗号分隔开并列在<code>SELECT</code>位置，也就是说它是我们想要查出的一列，</p><p>子查询中查出的是，班级表中的班级<code>id</code>与学生表中的班级<code>id</code>相同的行，注意 <code>WHERE c.class_id=s.class_id </code>这里就是别名用法的一个很好的体现，区分开了两张表中同样列名的列。</p><p>结果：</p><p><img src="https://pic.downk.cc/item/5e859338504f4bcb04d88208.jpg" alt="" loading="lazy"> 最后的<code>GROUP BY</code>可以理解为对重复行的去重，如果不加：</p><figure><img src="https://pic.downk.cc/item/5e859345504f4bcb04d88abb.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="在where中嵌套" tabindex="-1"><a class="header-anchor" href="#在where中嵌套" aria-hidden="true">#</a> 在WHERE中嵌套</h3><p>现要查出C语言成绩最高的学生的信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_subject <span class="token operator">=</span> <span class="token string">&#39;C语言&#39;</span>
  <span class="token operator">AND</span> student_score <span class="token operator">&gt;=</span> <span class="token keyword">ALL</span> <span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span>
      student_score
    <span class="token keyword">FROM</span> t_student
    <span class="token keyword">WHERE</span>
      student_subject <span class="token operator">=</span> <span class="token string">&#39;C语言&#39;</span>
  <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>结果：</p><p><img src="https://pic.downk.cc/item/5e85936a504f4bcb04d8a527.jpg" alt="" loading="lazy"> 这里出现了一个<code>ALL</code>，其为子查询运算符</p><p>分类：</p><ul><li><p><code>ALL</code>运算符 和子查询的结果逐一比较，必须全部满足时表达式的值才为真。</p></li><li><p><code>ANY</code>运算符 和子查询的结果逐一比较，其中一条记录满足条件则表达式的值就为真。</p></li><li><p><code>EXISTS/NOT EXISTS</code>运算符 <code>EXISTS</code>判断子查询是否存在数据，如果存在则表达式为真，反之为假。<code>NOT EXISTS</code>相反。</p></li></ul><p>在子查询或相关查询中，要求出某个列的最大值，通常都是用<code>ALL</code>来比较，大意为比其他行都要大的值即为最大值。</p><p>要查出C语言成绩比李四高的学生的信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_subject <span class="token operator">=</span> <span class="token string">&#39;C语言&#39;</span>
  <span class="token operator">AND</span> student_score <span class="token operator">&gt;</span><span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span>
      student_score
    <span class="token keyword">FROM</span> t_student
    <span class="token keyword">WHERE</span>
      student_name <span class="token operator">=</span> <span class="token string">&#39;李四&#39;</span>
      <span class="token operator">AND</span> student_subject <span class="token operator">=</span> <span class="token string">&#39;C语言&#39;</span>
  <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://pic.downk.cc/item/5e8593dd504f4bcb04d8f4ac.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>通过上面两例，应该可以明白子查询在<code>WHERE</code>中嵌套的作用。通过子查询中返回的列值来作为比较对象，在<code>WHERE</code>中运用不同的比较运算符来对其进行比较，从而得到结果。</p><p>现在我们回到最开始的问题，怎么查出每门课最高成绩的学生的信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student s1
<span class="token keyword">WHERE</span>
  s1<span class="token punctuation">.</span>student_score <span class="token operator">&gt;=</span> <span class="token keyword">ALL</span><span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span>
      s2<span class="token punctuation">.</span>student_score
    <span class="token keyword">FROM</span> t_student s2
    <span class="token keyword">WHERE</span>
      s1<span class="token punctuation">.</span>student_subject <span class="token operator">=</span> s2<span class="token punctuation">.</span>student_subject
  <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里就是上文提到的别名的第二种用法，主、子查询对同一张表操作，区分开位于内外表中相同的列名。</p><p>结果：</p><figure><img src="https://pic.downk.cc/item/5e8593f4504f4bcb04d90360.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="子查询的分类" tabindex="-1"><a class="header-anchor" href="#子查询的分类" aria-hidden="true">#</a> 子查询的分类</h3><ul><li><p>相关子查询</p><ul><li>执行依赖于外部查询的数据。</li><li>外部查询返回一行，子查询就执行一次。</li></ul></li><li><p>非相关子查询</p><ul><li>独立于外部查询的子查询。</li><li>子查询总共执行一次，执行完毕后后将值传递给外部查询。</li></ul></li></ul><p>上文提到的例子中，第一个例子求学生对应班级名的即为相关子查询，其中<code>WHERE c.class_id=s.class_id </code>即为相关条件。其他的例子均只对一张表进行操作，为非相关子查询。</p><p>需要注意的是相关子查询主查询执行一回，子查询就执行一回，十分耗费时间，尤其是当数据多的时候。</p><h2 id="组合查询" tabindex="-1"><a class="header-anchor" href="#组合查询" aria-hidden="true">#</a> 组合查询</h2><p>通过<code>UNION</code>运算符来将两张表纵向联接，基本方式为：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  列<span class="token number">1</span><span class="token punctuation">,</span>
  列<span class="token number">2</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">UNION</span>
<span class="token keyword">SELECT</span>
  列<span class="token number">3</span><span class="token punctuation">,</span>
  列<span class="token number">4</span>
<span class="token keyword">FROM</span> 表<span class="token number">2</span><span class="token punctuation">;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>UNION ALL</code>为保留重复行：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  列<span class="token number">1</span><span class="token punctuation">,</span>
  列<span class="token number">2</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">UNION</span> <span class="token keyword">ALL</span>
<span class="token keyword">SELECT</span>
  列<span class="token number">3</span><span class="token punctuation">,</span>
  列<span class="token number">4</span>
<span class="token keyword">FROM</span> 表<span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>组合查询并不是太实用，所以这里只是简单提一下，不举出例子了。</p><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>上文说过相关子查询不推荐使用，组合查询又用的少之又少，那需要关联的多张表我们怎么做？</p><p>这就是下一篇博文要详细说明的<code>SQL</code>的重点表联接、联接查询。而此篇博文目的是为了对嵌套查询、别名的用法等等打下基础，毕竟只是写法变了，思路还是相似的。</p>`,66);function k(b,m){const s=p("font");return d(),t("div",null,[o,a(s,{color:"red"},{default:e(()=>[i("注：`sum`只有`ALL`与`DISTINCT`两种计数规范，无`*`。")]),_:1}),r,a(s,{color:"red"},{default:e(()=>[i("注：这里只能求出最大年龄，要想显示年龄最大的学生全部信息，需要用到之后的子查询。")]),_:1}),u,a(s,{color:"red"},{default:e(()=>[i("牢记！")]),_:1}),v])}const f=c(l,[["render",k],["__file","3.html.vue"]]);export{f as default};
